function shouldAnimateStartupSpinner() {
  return Boolean(process.stdout.isTTY) &&
    process.env.CI !== "true" &&
    process.env.NO_COLOR !== "1" &&
    process.env.NO_COLOR !== "true" &&
    process.env.TERM !== "dumb";
